import React from "react";
import { useParams, useNavigate } from "react-router-dom";

export default function AppraisalView() {

  const { id } = useParams();
  const navigate = useNavigate();

  const appraisals = JSON.parse(localStorage.getItem("appraisals")) || [];
  const appraisal = appraisals.find(a => a.id == id);

  if (!appraisal) {
    return (
      <div style={{ padding: "25px" }}>
        <h2>Appraisal Not Found</h2>

        <button
          className="back-btn"
          onClick={() => navigate("/dashboard/appraisal")}
        >
          Go Back
        </button>

      </div>
    );
  }

  return (
    <div style={{ padding: "25px" }}>
      <h2>View Appraisal</h2>

      <p><b>Employee:</b> {appraisal.employeeName}</p>
      <p><b>Department:</b> {appraisal.department}</p>
      <p><b>Review Period:</b> {appraisal.period}</p>
      <p><b>Rating:</b> {appraisal.rating}</p>
      <p><b>Status:</b> {appraisal.status}</p>

      <br />

      <button
        className="back-btn"
        onClick={() => navigate("/dashboard/appraisal")}
      >
        Back
      </button>

    </div>
  );
}
